import React, { useEffect } from "react";
import { PRIORITY_META, STATUS_META } from "../utils/costants";

export default function FeatureModal({ feature, onClose }) {
  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  if (!feature) return null;

  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        background: "rgba(0, 0, 0, 0.6)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px",
      }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        style={{
          background: "white",
          borderRadius: "12px",
          boxShadow: "0 20px 60px rgba(0, 0, 0, 0.3)",
          maxWidth: "700px",
          width: "100%",
          maxHeight: "90vh",
          overflow: "auto",
        }}
      >
        {/* Header with gradient background */}
        <div
          style={{
            background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
            padding: "32px 32px 24px",
            borderRadius: "12px 12px 0 0",
            color: "white",
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
            <div>
              <h1 style={{ margin: "0 0 12px 0", fontSize: "28px", fontWeight: 700 }}>
                {feature.title}
              </h1>
              <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
                <span
                  style={{
                    display: "inline-block",
                    padding: "6px 12px",
                    background: "rgba(255, 255, 255, 0.2)",
                    borderRadius: "20px",
                    fontSize: "12px",
                    fontWeight: 600,
                    color: "white",
                  }}
                >
                  {sm?.icon} {feature.status}
                </span>
                <span
                  style={{
                    display: "inline-block",
                    padding: "6px 12px",
                    background: pm?.color || "rgba(255, 255, 255, 0.2)",
                    borderRadius: "20px",
                    fontSize: "12px",
                    fontWeight: 600,
                    color: "white",
                  }}
                >
                  {feature.priority} Priority
                </span>
              </div>
            </div>
            <button
              onClick={onClose}
              style={{
                background: "rgba(255, 255, 255, 0.2)",
                border: "none",
                fontSize: "24px",
                cursor: "pointer",
                color: "white",
                padding: "8px 12px",
                width: "40px",
                height: "40px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                borderRadius: "8px",
                transition: "background 0.2s",
              }}
              onMouseOver={(e) => e.target.style.background = "rgba(255, 255, 255, 0.3)"}
              onMouseOut={(e) => e.target.style.background = "rgba(255, 255, 255, 0.2)"}
            >
              ✕
            </button>
          </div>
        </div>

        {/* Body */}
        <div style={{ padding: "32px" }}>
          {/* Image at top if available */}
          {feature.image && (
            <div style={{ marginBottom: "28px" }}>
              <img
                src={`http://localhost:5000/api/features/images/${feature.image}`}
                alt={feature.title}
                style={{
                  width: "100%",
                  maxHeight: "350px",
                  borderRadius: "8px",
                  border: "1px solid #e5e7eb",
                  objectFit: "cover",
                }}
              />
            </div>
          )}

          {/* Description as paragraph */}
          <div style={{ marginBottom: "28px" }}>
            <h3 style={{ fontSize: "14px", fontWeight: 700, color: "#667eea", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: "12px" }}>
              Description
            </h3>
            <p
              style={{
                fontSize: "15px",
                color: "#374151",
                lineHeight: "1.8",
                whiteSpace: "pre-wrap",
                margin: 0,
                fontWeight: 400,
              }}
            >
              {feature.description}
            </p>
          </div>

          {/* Details grid */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "24px",
              padding: "24px",
              background: "#f9fafb",
              borderRadius: "8px",
              marginBottom: "24px",
            }}
          >
            <div>
              <p style={{ fontSize: "12px", fontWeight: 700, color: "#9ca3af", textTransform: "uppercase", letterSpacing: "0.5px", margin: "0 0 8px 0" }}>
                Status
              </p>
              <div
                style={{
                  fontSize: "16px",
                  fontWeight: 600,
                  color: sm?.color || "#6b7280",
                  display: "flex",
                  alignItems: "center",
                  gap: "6px",
                }}
              >
                {sm?.icon} {feature.status}
              </div>
            </div>
            <div>
              <p style={{ fontSize: "12px", fontWeight: 700, color: "#9ca3af", textTransform: "uppercase", letterSpacing: "0.5px", margin: "0 0 8px 0" }}>
                Priority
              </p>
              <div
                style={{
                  fontSize: "16px",
                  fontWeight: 600,
                  color: pm?.color || "#6b7280",
                }}
              >
                {feature.priority}
              </div>
            </div>
          </div>

          {/* Close Button */}
          <button
            onClick={onClose}
            style={{
              width: "100%",
              padding: "12px 16px",
              background: "#667eea",
              border: "none",
              borderRadius: "8px",
              fontSize: "15px",
              fontWeight: 600,
              cursor: "pointer",
              color: "white",
              transition: "background 0.2s",
            }}
            onMouseOver={(e) => e.target.style.background = "#764ba2"}
            onMouseOut={(e) => e.target.style.background = "#667eea"}
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
}
